      unidade_preferida: nullableStr(resumoRepasseJson.unidade_preferida || row.unidade_preferida),
      servico_interesse: nullableStr(resumoRepasseJson.servico_interesse || row.servico_interesse),
      data_hora_avaliacao: nullableStr(resumoRepasseJson.data_hora_avaliacao || row.data_hora_avaliacao),
      comprovante_recebido: comprovanteRecebido,
      tipo_comprovante: nullableStr(resumoRepasseJson.tipo_comprovante || row.tipo_comprovante),
      observacoes: nullableStr(resumoRepasseJson.observacoes || inferObservacoesRepasse(row))
    }
  };

  return {
    json: {
      inputs
    }
  };
});

function removeEmpty(value) {
  if (Array.isArray(value)) {
    return value
      .map(removeEmpty)
      .filter(v => v !== null && v !== undefined && v !== '');
  }

  if (value && typeof value === 'object') {
    const out = {};
    for (const [key, val] of Object.entries(value)) {
      const cleaned = removeEmpty(val);

      if (cleaned === null || cleaned === undefined || cleaned === '') continue;
      if (Array.isArray(cleaned) && cleaned.length === 0) continue;
      if (
        typeof cleaned === 'object' &&
        !Array.isArray(cleaned) &&
        Object.keys(cleaned).length === 0
      ) continue;

      out[key] = cleaned;
    }
    return out;
  }

  return value;
}

const baseItem = $('Histórico Atualizado').first().json;
const histItem = $json || {};

const output = {
  ...baseItem,

  message: {
    ...baseItem.message,
    content:
      histItem?.message?.content ||
      histItem?.message ||
      histItem?.last_user_message ||
      baseItem?.message?.content ||
      '',
    historico:
      histItem?.message?.historico ||
      histItem?.source ||
      'atual'
  },

  inputs: {
    ...(baseItem.inputs || {}),
    ...(histItem.inputs || {}),
  }
};

return [{ json: (output) }];

const item = $json;

// prioridade de leitura
const statusAtual =
  item?.memory?.status_lead ||
  item?.status_lead ||
  item?.inputs?.status_lead ||
  'NOVO_LEAD';

const shouldReply = Boolean(item?.should_reply);

const mensagem = String(
  item?.message?.content_last_message ||
  item?.message?.content ||
  ''
).trim();

const temAnexo = Boolean(item?.message?.has_attachment);
const supportedInput = Boolean(item?.inputs?.supported_input);

// labels
const labels = Array.isArray(item?.chatwoot?.labels) ? item.chatwoot.labels : [];

// flags de estado
const encerrado =
  Boolean(item?.memory?.encerrado) ||
  String(statusAtual).startsWith('ENCERRADO');

const transferidoHumano =
  statusAtual === 'TRANSFERIDO_FLAVIA' ||
  Boolean(item?.memory?.deve_repassar_humano);

// flags de mensagem
const mensagemVazia = !mensagem;
const mensagemDuplicada = false;
const mensagemPrivada = Boolean(item?.message?.private);

const tipoEntradaSuportada =
  supportedInput &&
  item?.inputs?.interpreted_status === 'ok';

// comprovante provável
const statusPermiteComprovante = [
  'AGUARDANDO_PAGAMENTO',
  'COMPROVANTE_RECEBIDO',
  'AGUARDANDO_ESCOLHA_HORARIO'
].includes(statusAtual);

const podeSerComprovante =
  temAnexo &&
  statusPermiteComprovante;

// regra final
let rota = 'PROCESSAR_BRUNA';
let motivo = 'fluxo_padrao';

if (!shouldReply) {
  rota = 'IGNORAR';
  motivo = 'should_reply_false';
} else if (mensagemPrivada) {
  rota = 'IGNORAR';
  motivo = 'mensagem_privada';
} else if (!tipoEntradaSuportada) {
  rota = 'IGNORAR';
  motivo = 'input_nao_suportado';
} else if (encerrado) {
  rota = 'IGNORAR';
  motivo = 'lead_encerrado';
} else if (transferidoHumano) {
  rota = 'REPASSE_HUMANO';
  motivo = 'ja_transferido_para_flavia';
} else if (podeSerComprovante) {
  rota = 'TRILHA_COMPROVANTE';
  motivo = 'anexo_em_status_de_pagamento';
} else if (mensagemVazia && !temAnexo) {
  rota = 'IGNORAR';
  motivo = 'mensagem_vazia_sem_anexo';
} else {
  rota = 'PROCESSAR_BRUNA';
  motivo = 'novo_lead_ou_fluxo_conversacional';
}

return [
  {
    json: {
      roteamento: {
        rota,
        motivo,
        status_atual: statusAtual,
        should_reply: shouldReply,
        encerrado,
        transferido_humano: transferidoHumano,
        tem_anexo: temAnexo,
        pode_ser_comprovante: podeSerComprovante,
        mensagem_vazia: mensagemVazia,
        mensagem_duplicada: mensagemDuplicada,
        usar_processar_bruna: rota === 'PROCESSAR_BRUNA',
        usar_trilha_comprovante: rota === 'TRILHA_COMPROVANTE',
        usar_trilha_repasse: rota === 'REPASSE_HUMANO',
        ignorar_evento: rota === 'IGNORAR',
        labels
      },
      ...item
    }
  }
];

function pick(...values) {
  for (const v of values) {
    if (v !== undefined && v !== null && String(v).trim() !== '') return v;
  }
  return '';
}

function norm(v) {
  return String(v ?? '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .trim()
    .toLowerCase();
}

function isTrueLike(v) {
  const n = norm(v);
  return v === true || ['true', '1', 'sim', 'yes'].includes(n);
}

function isFalseLike(v) {
  const n = norm(v);
  return v === false || ['false', '0', 'nao', 'não', 'no'].includes(n);
}

function parseAgeYears(ageValue, ageText) {
  if (ageValue !== undefined && ageValue !== null && String(ageValue).trim() !== '') {
    const n = Number(String(ageValue).replace(',', '.'));
    if (!Number.isNaN(n)) return n;
  }

  const txt = norm(ageText);
  if (!txt) return null;

  const yearMatch = txt.match(/(\d+(?:[.,]\d+)?)\s*ano/);
  if (yearMatch) {
    const n = Number(yearMatch[1].replace(',', '.'));
    return Number.isNaN(n) ? null : n;
  }

  const monthMatch = txt.match(/(\d+(?:[.,]\d+)?)\s*mes/);
  if (monthMatch) {
    const n = Number(monthMatch[1].replace(',', '.'));
    return Number.isNaN(n) ? null : n / 12;
  }

  return null;
}

function buildMessages(reason, tutorNome, caoNome) {
  const nomeTutor = String(tutorNome || '').trim();
  const nomeCao = String(caoNome || '').trim();
  const abertura = nomeTutor ? `Oi, ${nomeTutor}.` : 'Entendi.';

  if (reason === 'RACA_POTENCIAL_DANO') {
    return [
      abertura,
      'Nossa equipe não tem treinamento nem experiência com cães de grande potencial de dano, então infelizmente não conseguimos seguir com o atendimento por aqui.',
      nomeCao ? `Agradeço por ter nos contado sobre o ${nomeCao}.` : 'Agradeço pela compreensão.'
    ];
  }

  if (reason === 'MACHO_NAO_CASTRADO') {
    return [
      abertura,
      'Para frequentar a creche ou o hotel, machos a partir de 8 meses precisam ser castrados.',
      'Como esse requisito não está atendido agora, infelizmente não conseguimos seguir por aqui.'
    ];
  }

  return ['Entendi.'];
}

