    cao_vacinas_ok: 'nao_informado',
    cao_antipulgas_ok: 'nao_informado',
    cao_vermifugacao_ok: 'nao_informado',
    cao_sociavel: 'nao_informado',
    cao_reativo: 'nao_informado',
    possui_relatorio_veterinario: '',
    unidade_preferida: 'nao_definida',
    servico_interesse: '',
    periodo_desejado: '',
    data_desejada: '',
    comprovante_recebido: false,
    tipo_comprovante: 'nao_informado',
    data_hora_pre_reserva: null,
    responsavel_humano: 'Flavia',
    observacoes: ''
  };
}

function defaultResumoInternoRepasse() {
  return {
    repassar_para: '',
    motivo: '',
    tutor_nome: '',
    tutor_telefone: '',
    cao_nome: '',
    cao_idade_anos: '',
    cao_raca: '',
    cao_porte: '',
    cao_sexo: '',
    cao_castrado: '',
    cao_vacinas_ok: '',
    cao_antipulgas_ok: '',
    cao_sociavel: '',
    cao_reativo: '',
    unidade_preferida: '',
    servico_interesse: '',
    data_hora_avaliacao: null,
    comprovante_recebido: false,
    tipo_comprovante: '',
    observacoes: ''
  };
}

const montaBrunaItems = $items('Monta Bruna', 0, 0) || [];

return items.map((item, index) => {
  const current = item.json || {};
  const monta = montaBrunaItems[index]?.json || {};

  const brunaOutput =
    current.output && typeof current.output === 'object'
      ? current.output
      : current;

  const originalInputs =
    monta.inputs && typeof monta.inputs === 'object'
      ? monta.inputs
      : (current.inputs && typeof current.inputs === 'object' ? current.inputs : {});

  const mensagensResposta = Array.isArray(brunaOutput.mensagens_resposta)
    ? brunaOutput.mensagens_resposta
    : [];

  const j = {
    message: {
      ...(monta.message || current.message || {}),
      clean_answer: mensagensResposta.length > 0
        ? mensagensResposta.join('\n\n')
        : pick(
            monta.message?.clean_answer,
            current.message?.clean_answer,
            monta.message?.content,
            current.message?.content
          )
    },
    lead: {
      ...(monta.lead || current.lead || {})
    },
    chatwoot: {
      ...(monta.chatwoot || current.chatwoot || {})
    },
    inputs: {
      ...originalInputs,
      ...brunaOutput
    }
  };

  const inputs = j.inputs;

  inputs.resumo_lead = {
    ...defaultResumoLead(),
    ...(originalInputs.resumo_lead || {}),
    ...(brunaOutput.resumo_lead || {})
  };

  inputs.resumo_interno_repasse = {
    ...defaultResumoInternoRepasse(),
    ...(originalInputs.resumo_interno_repasse || {}),
    ...(brunaOutput.resumo_interno_repasse || {})
  };

  if (!Array.isArray(inputs.mensagens_resposta) || inputs.mensagens_resposta.length === 0) {
    inputs.mensagens_resposta = mensagensResposta.length > 0
      ? mensagensResposta
      : (pick(j.message.clean_answer) ? [j.message.clean_answer] : []);
  }

  if (!inputs.regras_raca || typeof inputs.regras_raca !== 'object') inputs.regras_raca = originalInputs.regras_raca || {};
  if (!inputs.calendario || typeof inputs.calendario !== 'object') inputs.calendario = originalInputs.calendario || {};

  inputs.status_lead = inputs.status_lead ?? '';
  inputs.ultima_intencao = inputs.ultima_intencao ?? '';
  inputs.evento_sistema = inputs.evento_sistema ?? '';
  inputs.proxima_acao = inputs.proxima_acao ?? '';

  inputs.deve_repassar_humano = Boolean(inputs.deve_repassar_humano);
  inputs.motivo_repasse = inputs.motivo_repasse ?? '';
  inputs.deve_enviar_guia = Boolean(inputs.deve_enviar_guia);
  inputs.deve_solicitar_pagamento = Boolean(inputs.deve_solicitar_pagamento);
  inputs.deve_consultar_agenda = Boolean(inputs.deve_consultar_agenda);
  inputs.deve_criar_pre_reserva = Boolean(inputs.deve_criar_pre_reserva);
  inputs.deve_encerrar_conversa = Boolean(inputs.deve_encerrar_conversa);

  const resumo = inputs.resumo_lead;
  const resumoInternoRepasse = inputs.resumo_interno_repasse;
  const regrasRaca = inputs.regras_raca || {};
  const message = j.message || {};
  const lead = j.lead || {};

  const tutorNome = pick(
    resumo.tutor_nome,
    inputs.nome_tutor,
    inputs.lead_name,
    lead.sender_name
  );

  const tutorTelefone = pick(
    resumo.tutor_telefone,
    inputs.phone,
    inputs.lead_phone,
    lead.phone
  );

  const caoNome = pick(
    resumo.cao_nome,
    inputs.nome_cao
  );

  const sexo = norm(pick(
    resumo.cao_sexo,
    inputs.cao_sexo
  ));

  const castrado = pick(
    resumo.cao_castrado,
    inputs.cao_castrado
  );

  const idadeAnos = parseAgeYears(
    pick(
      resumo.cao_idade_anos,
      inputs.idade_cao_anos,
      inputs.cao_idade_anos
    ),
    pick(
      resumo.cao_idade_texto,
      inputs.idade_cao_texto,
      inputs.cao_idade_texto,
      inputs.mensagem_ultima_lead,
      inputs.last_user_message,
      message.content
    )
  );

  const textoContexto = norm([
  String(message?.content?.history_for_crm || ''),
  String(message?.content || ''),
  String(inputs?.mensagem_ultima_lead || ''),
  String(resumo?.cao_nome || ''),
  String(resumo?.cao_castrado || ''),
  String(resumo?.cao_sexo || '')
].join(' '));

const multiCaes =
  /duas|dois|elas sao|eles sao|uma .* outra|uma esta .* a outra/.test(textoContexto) ||
  String(resumo?.cao_nome || '').includes(' e ') ||
  String(resumo?.cao_castrado || '').includes(',');

const femeaContexto =
  sexo.includes('femea') ||
  /femea|cadelinha|cadelas|duas femeas/.test(textoContexto);

const castracaoMista =
  /castrada/.test(textoContexto) &&
  /nao castrada|ainda nao|nao/.test(textoContexto);

  const potencialDano = isTrueLike(regrasRaca.potencial_dano);

  if (
  (inputs?.ultima_intencao === 'MACHO_NAO_CASTRADO' && (femeaContexto || multiCaes)) ||
  (multiCaes && femeaContexto && castracaoMista)
) {
  inputs.status_lead = 'TRANSFERIDO_FLAVIA';
  inputs.ultima_intencao = 'PEDIU_HUMANO';
  inputs.evento_sistema = 'REPASSE_FLAVIA';
  inputs.deve_repassar_humano = true;
  inputs.motivo_repasse = 'caso_ambiguo_multiplos_caes';
  inputs.deve_enviar_guia = false;
  inputs.deve_solicitar_pagamento = false;
  inputs.deve_consultar_agenda = false;
  inputs.deve_criar_pre_reserva = false;
  inputs.deve_encerrar_conversa = false;

  inputs.mensagens_resposta = [
    'Entendi. Como são duas cadelinhas e o caso tem detalhes específicos, vou encaminhar para a Flávia seguir com você certinho.'
  ];

  inputs.proxima_acao = 'repassar para humano por caso ambiguo com multiplos caes';
  inputs.regra_nao_perfil_objetivo_acionada = false;
  inputs.regra_nao_perfil_motivo = '';

  return { json: j };
}

  let motivoNaoPerfil = '';

  if (potencialDano) {
    motivoNaoPerfil = 'RACA_POTENCIAL_DANO';
  } else if (sexo === 'macho' && idadeAnos !== null && idadeAnos >= 0.6667 && isFalseLike(castrado)) {
    motivoNaoPerfil = 'MACHO_NAO_CASTRADO';
  }

  if (motivoNaoPerfil) {
    const mensagens = buildMessages(motivoNaoPerfil, tutorNome, caoNome);

    inputs.regra_nao_perfil_objetivo_acionada = true;
    inputs.regra_nao_perfil_motivo = motivoNaoPerfil;

    inputs.status_lead = 'ENCERRADO_NAO_PERFIL';
    inputs.ultima_intencao = motivoNaoPerfil;
    inputs.evento_sistema = 'CONVERSA_ENCERRADA';

    inputs.deve_repassar_humano = false;
    inputs.motivo_repasse = '';
    inputs.deve_enviar_guia = false;
    inputs.deve_solicitar_pagamento = false;
    inputs.deve_consultar_agenda = false;
    inputs.deve_criar_pre_reserva = false;
    inputs.deve_encerrar_conversa = true;

    inputs.mensagens_resposta = mensagens;
    j.message.clean_answer = mensagens.join('\n\n');

    inputs.proxima_acao =
      motivoNaoPerfil === 'RACA_POTENCIAL_DANO'
        ? 'encerrar atendimento por nao perfil objetivo devido a raca com grande potencial de dano'
        : 'encerrar atendimento por nao perfil objetivo devido a macho nao castrado com 8 meses ou mais';

    inputs.resumo_lead = {
      ...resumo,
      tutor_nome: String(tutorNome || resumo.tutor_nome || ''),
      tutor_telefone: String(tutorTelefone || resumo.tutor_telefone || ''),
