      cao_porte: String(pick(resumo.cao_porte, inputs.cao_porte, '') || ''),
      cao_sexo: String(pick(resumo.cao_sexo, inputs.cao_sexo, '') || ''),
      cao_castrado: String(pick(resumo.cao_castrado, inputs.cao_castrado, '') || ''),
      cao_vacinas_ok: String(pick(resumo.cao_vacinas_ok, inputs.cao_vacinas_ok, '') || ''),
      cao_antipulgas_ok: String(pick(resumo.cao_antipulgas_ok, inputs.cao_antipulgas_ok, '') || ''),
      cao_sociavel: String(pick(resumo.cao_sociavel, inputs.cao_sociavel, '') || ''),
      cao_reativo: String(pick(resumo.cao_reativo, inputs.cao_reativo, '') || ''),
      unidade_preferida: String(pick(resumo.unidade_preferida, inputs.unidade_preferida, '') || ''),
      servico_interesse: String(pick(resumo.servico_interesse, inputs.servico_interesse, '') || ''),
      data_hora_avaliacao: null,
      comprovante_recebido: false,
      tipo_comprovante: '',
