  }

  inputs.regra_nao_perfil_objetivo_acionada = false;
  inputs.regra_nao_perfil_motivo = '';

  const statusPagamento = norm(pick(inputs.status_pagamento));

  const comprovanteRecebido =
    isTrueLike(inputs.comprovante_recebido) ||
    isTrueLike(resumo.comprovante_recebido);

  const podeIrPraAgenda =
    comprovanteRecebido ||
    ['comprovante_recebido', 'validacao_humana_pendente', 'aprovado_humano'].includes(statusPagamento);

  const statusLeadAtual = pick(inputs.status_lead);
  const eventoAtual = pick(inputs.evento_sistema);

  const tentouAgendaSemPagamento =
    !podeIrPraAgenda &&
    (
      statusLeadAtual === 'AGUARDANDO_ESCOLHA_HORARIO' ||
