const item = $input.first().json;

function sanitizeString(value) {
  return String(value)
    .replace(/\[object Object\]/gi, '')
    .replace(/[\u200B-\u200D\u2060\uFEFF]/g, ' ')
    .replace(/\uFFFD/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function deepSanitize(value, keyPath = '') {
  const protectedKeys = [
    'data_url',
    'source_id',
    'pubsub_token',
    'hmac_verified'
  ];

  const currentKey = keyPath.split('.').pop() || '';

  if (protectedKeys.includes(currentKey)) {
    return value;
  }

  if (typeof value === 'string') {
    return sanitizeString(value);
  }

  if (Array.isArray(value)) {
    return value.map((item, index) => deepSanitize(item, `${keyPath}[${index}]`));
  }

  if (value && typeof value === 'object') {
    const output = {};
    for (const [key, val] of Object.entries(value)) {
      output[key] = deepSanitize(val, keyPath ? `${keyPath}.${key}` : key);
    }
    return output;
  }

  return value;
}

const sanitized = deepSanitize(item);

return [{ json: sanitized }];

const item = $input.first().json;

const res = item?.parsed_output || item?.bruna_json || item;
const guard = item?.inputs?.guardrails || {};

const firstNameRaw =
  item?.lead?.sender_name ||
  item?.lead_name ||
  res?.resumo_lead?.tutor_nome ||
  '';

const firstName = String(firstNameRaw).trim().split(/\s+/)[0] || '';

const hello = firstName
  ? `Olá, ${firstName}! Sou a Bruna da AuAu Creche Canina 🐶🩵. Vou cuidar do seu atendimento hoje.`
  : 'Olá! Sou a Bruna da AuAu Creche Canina 🐶🩵. Vou cuidar do seu atendimento hoje.';

const forcedIntent = guard?.force_intent || '';
const isHotel = forcedIntent === 'INTERESSE_HOTEL';

if (
  guard?.flow_mode === 'OPENING_TRAFFIC' &&
  (
    res?.status_lead === 'AGUARDANDO_PAGAMENTO' ||
    res?.ultima_intencao === 'ACEITOU_AVALIACAO' ||
    res?.evento_sistema === 'PIX_SOLICITADO' ||
    res?.deve_solicitar_pagamento === true
  )
) {
  res.status_lead = 'COLETANDO_DADOS';
  res.ultima_intencao = forcedIntent || 'INTERESSE_CRECHE';
  res.evento_sistema = 'FORMULARIO_RECEBIDO';
  res.mensagens_resposta = isHotel
    ? [
        hello,
        'Vi que você tem interesse no hotel e também em entender como funciona a avaliação.',
        'Pode me informar o nome, a idade, a raça e o porte do seu cãozinho? Se preferir, pode me mandar por áudio também.'
      ]
    : [
        hello,
        'Que bom receber sua mensagem. Vou te explicar tudo certinho por aqui.',
        'Pode me informar o nome, a idade, a raça e o porte do seu cãozinho? Se preferir, pode me mandar por áudio também.'
      ];
  res.proxima_acao = 'coletar dados iniciais do cão antes de qualquer cobrança';
  res.deve_solicitar_pagamento = false;
  res.deve_consultar_agenda = false;
  res.deve_criar_pre_reserva = false;
  res.deve_repassar_humano = false;
  res.motivo_repasse = '';
  res.deve_encerrar_conversa = false;
}

if (guard?.flow_mode === 'RECOVER_INFO') {
  res.status_lead = 'QUALIFICANDO';
  res.ultima_intencao = 'PEDIU_VALOR';
  res.evento_sistema = '';
  res.mensagens_resposta = isHotel
    ? [
        'Claro. Para o hotel, primeiro o cão passa pela avaliação e depois pela adaptação, tudo para garantir segurança e bem-estar.',
        'Pode me passar também o nome, a idade, a raça e o porte do seu cãozinho para eu te orientar certinho?'
      ]
    : [
        'Claro. Vou te explicar certinho como funciona.',
        'Antes de seguir para a avaliação, eu preciso entender melhor o perfil do seu cãozinho.',
        'Pode me passar o nome, a idade, a raça e o porte dele?'
      ];
  res.proxima_acao = 'responder dúvida de preço e seguir qualificação com suavidade';
  res.deve_solicitar_pagamento = false;
  res.deve_consultar_agenda = false;
  res.deve_criar_pre_reserva = false;
  res.deve_repassar_humano = false;
  res.motivo_repasse = '';
  res.deve_encerrar_conversa = false;
}

item.parsed_output = res;
return [{ json: item }];

