function safeParse(value, fallback) {
  if (value === null || value === undefined || value === '') return fallback;
  if (typeof value === 'object') return value;
  try {
    return JSON.parse(value);
  } catch {
    return fallback;
  }
}

function str(value, fallback = '') {
  if (value === null || value === undefined) return fallback;
  return String(value);
}

function nullableStr(value) {
  if (value === null || value === undefined || value === '') return '';
  return String(value);
}

function bool(value, fallback = false) {
  if (value === null || value === undefined || value === '') return fallback;
  if (typeof value === 'boolean') return value;
  return Number(value) === 1;
}

function inferProximaAcao(row) {
  const status = str(row.status_lead, '');
  const statusPagamento = str(row.status_pagamento, '');
  const guiaEnviado = bool(row.guia_enviado, false);
  const comprovanteRecebido = bool(row.comprovante_recebido, false);
  const deveRepassarHumano = bool(row.deve_repassar_humano, false);
  const preReservaCriada = bool(row.pre_reserva_criada, false);
  const encerrado = bool(row.encerrado, false);

  if (encerrado || status.startsWith('ENCERRADO')) return 'ENCERRAR_CONVERSA';
  if (deveRepassarHumano || status === 'TRANSFERIDO_FLAVIA') return 'REPASSAR_HUMANO';
  if (preReservaCriada || status === 'PRE_RESERVA_CRIADA') return 'CONFIRMAR_PRE_RESERVA';
  if (status === 'AGUARDANDO_ESCOLHA_HORARIO') return 'ENVIAR_OU_CONFIRMAR_HORARIOS';
  if (comprovanteRecebido || status === 'COMPROVANTE_RECEBIDO') return 'VALIDAR_COMPROVANTE';
  if (status === 'AGUARDANDO_PAGAMENTO' || statusPagamento === 'aguardando_pagamento') return 'SOLICITAR_PAGAMENTO';
  if (status === 'APTO_PARA_AVALIACAO' && !guiaEnviado) return 'ENVIAR_GUIA';
  if (status === 'APTO_PARA_AVALIACAO' && guiaEnviado) return 'SOLICITAR_PAGAMENTO';
  if (status === 'PRE_REPROVADO') return 'EXPLICAR_PRE_REPROVACAO';
  if (status === 'NOVO_LEAD' || status === 'COLETANDO_DADOS' || status === 'QUALIFICANDO') return 'PEDIR_DADOS_CAO';

  return '';
}

function inferObservacoesResumoLead(row) {
  return nullableStr(
    row.observacoes ||
    row.motivo_pre_reprovacao ||
    row.motivo_repasse ||
    ''
  );
}

function inferObservacoesRepasse(row) {
  return nullableStr(
    row.observacoes_internas ||
    row.motivo_repasse ||
    row.motivo_pre_reprovacao ||
    ''
  );
}

return $input.all().map((item) => {
  const row = Array.isArray(item.json) ? (item.json[0] || {}) : (item.json || {});

  const resumoLeadJson = safeParse(row.resumo_lead_json, {});
  const resumoRepasseJson = safeParse(row.resumo_interno_repasse_json, {});

  const telefone = row.telefone_e164 || row.phone || '';
  const proximaAcao = inferProximaAcao(row);

  const deveRepassarHumano = bool(row.deve_repassar_humano, false);
  const comprovanteRecebido = bool(row.comprovante_recebido, false);
  const guiaEnviado = bool(row.guia_enviado, false);
  const preReservaCriada = bool(row.pre_reserva_criada, false);
  const encerrado = bool(row.encerrado, false);

  const inputs = {
    status_lead: str(row.status_lead, 'NOVO_LEAD'),
    ultima_intencao: row.ultima_intencao ?? null,
    evento_sistema: row.evento_sistema_atual ?? row.evento_sistema ?? null,
    mensagens_resposta: [],

    resumo_lead: {
      tutor_nome: nullableStr(resumoLeadJson.tutor_nome || row.nome_tutor),
      tutor_telefone: nullableStr(resumoLeadJson.tutor_telefone || resumoLeadJson.telefone_e164 || telefone),
      cao_nome: nullableStr(resumoLeadJson.cao_nome || row.nome_cao),
      cao_idade_anos: nullableStr(resumoLeadJson.cao_idade_anos || row.idade_cao_anos),
      cao_raca: nullableStr(resumoLeadJson.cao_raca || row.cao_raca),
      cao_porte: nullableStr(resumoLeadJson.cao_porte || row.cao_porte),
      cao_sexo: nullableStr(resumoLeadJson.cao_sexo || row.cao_sexo),
      cao_castrado: nullableStr(resumoLeadJson.cao_castrado || row.cao_castrado),
      cao_no_cio: nullableStr(resumoLeadJson.cao_no_cio || row.cao_no_cio),
      cao_vacinas_ok: nullableStr(resumoLeadJson.cao_vacinas_ok || row.cao_vacinas_ok),
      cao_antipulgas_ok: nullableStr(resumoLeadJson.cao_antipulgas_ok || row.cao_antipulgas_ok),
      cao_vermifugacao_ok: nullableStr(resumoLeadJson.cao_vermifugacao_ok || row.cao_vermifugacao_ok),
      cao_sociavel: nullableStr(resumoLeadJson.cao_sociavel || row.cao_sociavel),
      cao_reativo: nullableStr(resumoLeadJson.cao_reativo || row.cao_reativo),
      unidade_preferida: nullableStr(resumoLeadJson.unidade_preferida || row.unidade_preferida),
      servico_interesse: nullableStr(resumoLeadJson.servico_interesse || row.servico_interesse),
      periodo_desejado: nullableStr(resumoLeadJson.periodo_desejado || row.periodo_desejado),
      data_desejada: nullableStr(resumoLeadJson.data_desejada || row.data_desejada),
      origem_lead: nullableStr(resumoLeadJson.origem_lead || row.origem_lead),
      comprovante_recebido: comprovanteRecebido,
      tipo_comprovante: nullableStr(resumoLeadJson.tipo_comprovante || row.tipo_comprovante),
      data_hora_pre_reserva: nullableStr(resumoLeadJson.data_hora_pre_reserva || row.data_hora_pre_reserva),
      responsavel_humano: nullableStr(resumoLeadJson.responsavel_humano || row.responsavel_humano),
      observacoes: nullableStr(resumoLeadJson.observacoes || inferObservacoesResumoLead(row))
    },

    proxima_acao: proximaAcao,
    deve_repassar_humano: deveRepassarHumano,
    motivo_repasse: nullableStr(row.motivo_repasse),
    deve_enviar_guia: !guiaEnviado && str(row.status_lead) === 'APTO_PARA_AVALIACAO',
    deve_solicitar_pagamento: (
      str(row.status_lead) === 'AGUARDANDO_PAGAMENTO' ||
      str(row.status_pagamento) === 'aguardando_pagamento' ||
      (str(row.status_lead) === 'APTO_PARA_AVALIACAO' && guiaEnviado && !comprovanteRecebido)
    ),
    deve_consultar_agenda: str(row.status_lead) === 'AGUARDANDO_ESCOLHA_HORARIO',
    deve_criar_pre_reserva: !preReservaCriada && !!row.data_hora_avaliacao && comprovanteRecebido,
    deve_encerrar_conversa: encerrado || str(row.status_lead).startsWith('ENCERRADO'),
    mensagem_ultima_lead: nullableStr(row.mensagem_ultima_lead),
    mensagem_ultima_bruna: nullableStr(row.mensagem_ultima_bruna),

    resumo_interno_repasse: {
      repassar_para: nullableStr(resumoRepasseJson.repassar_para || row.responsavel_humano),
      motivo: nullableStr(resumoRepasseJson.motivo || row.motivo_repasse),
      tutor_nome: nullableStr(resumoRepasseJson.tutor_nome || row.nome_tutor),
      tutor_telefone: nullableStr(resumoRepasseJson.tutor_telefone || telefone),
      cao_nome: nullableStr(resumoRepasseJson.cao_nome || row.nome_cao),
      cao_idade_anos: nullableStr(resumoRepasseJson.cao_idade_anos || row.idade_cao_anos),
      cao_raca: nullableStr(resumoRepasseJson.cao_raca || row.cao_raca),
      cao_porte: nullableStr(resumoRepasseJson.cao_porte || row.cao_porte),
      cao_sexo: nullableStr(resumoRepasseJson.cao_sexo || row.cao_sexo),
      cao_castrado: nullableStr(resumoRepasseJson.cao_castrado || row.cao_castrado),
      cao_vacinas_ok: nullableStr(resumoRepasseJson.cao_vacinas_ok || row.cao_vacinas_ok),
      cao_antipulgas_ok: nullableStr(resumoRepasseJson.cao_antipulgas_ok || row.cao_antipulgas_ok),
      cao_sociavel: nullableStr(resumoRepasseJson.cao_sociavel || row.cao_sociavel),
      cao_reativo: nullableStr(resumoRepasseJson.cao_reativo || row.cao_reativo),
      unidade_preferida: nullableStr(resumoRepasseJson.unidade_preferida || row.unidade_preferida),
      servico_interesse: nullableStr(resumoRepasseJson.servico_interesse || row.servico_interesse),
      data_hora_avaliacao: nullableStr(resumoRepasseJson.data_hora_avaliacao || row.data_hora_avaliacao),
      comprovante_recebido: comprovanteRecebido,
      tipo_comprovante: nullableStr(resumoRepasseJson.tipo_comprovante || row.tipo_comprovante),
      observacoes: nullableStr(resumoRepasseJson.observacoes || inferObservacoesRepasse(row))
    }
  };

  return {
    json: {
      inputs
    }
  };
});

function removeEmpty(value) {
  if (Array.isArray(value)) {
    return value
      .map(removeEmpty)
      .filter(v => v !== null && v !== undefined && v !== '');
  }

  if (value && typeof value === 'object') {
    const out = {};
    for (const [key, val] of Object.entries(value)) {
      const cleaned = removeEmpty(val);

      if (cleaned === null || cleaned === undefined || cleaned === '') continue;
      if (Array.isArray(cleaned) && cleaned.length === 0) continue;
      if (
        typeof cleaned === 'object' &&
        !Array.isArray(cleaned) &&
        Object.keys(cleaned).length === 0
      ) continue;

      out[key] = cleaned;
    }
    return out;
  }

  return value;
}

