  if (reason === 'RACA_POTENCIAL_DANO') {
    return [
      abertura,
      'Nossa equipe não tem treinamento nem experiência com cães de grande potencial de dano, então infelizmente não conseguimos seguir com o atendimento por aqui.',
      nomeCao ? `Agradeço por ter nos contado sobre o ${nomeCao}.` : 'Agradeço pela compreensão.'
    ];
  }

  if (reason === 'MACHO_NAO_CASTRADO') {
    return [
      abertura,
      'Para frequentar a creche ou o hotel, machos a partir de 8 meses precisam ser castrados.',
      'Como esse requisito não está atendido agora, infelizmente não conseguimos seguir por aqui.'
    ];
  }

  return ['Entendi.'];
}

