const TIMEZONE = 'America/Sao_Paulo';
const MIN_DIFF_MINUTES = 30*60; // 30h

// Se vier de um único item com array dentro, usa ele.
// Se vier item por item, também funciona.
let rawSlots = [];

if (items.length === 1 && Array.isArray(items[0].json)) {
  rawSlots = items[0].json;
} else if (items.length === 1 && Array.isArray(items[0].json.slots)) {
  rawSlots = items[0].json.slots;
} else {
  rawSlots = items.map(item => item.json);
}

function getShift(hour) {
  if (hour < 12) return 'manha';
  if (hour < 18) return 'tarde';
  return 'noite';
}

function formatHour(hour, minute) {
  if (minute === 0) {
    return `${hour}h`;
  }

  return `${hour}h${String(minute).padStart(2, '0')}`;
}

function getLocalParts(utcString, timeZone = TIMEZONE) {
  const date = new Date(utcString);

  const formatter = new Intl.DateTimeFormat('pt-BR', {
    timeZone,
    weekday: 'long',
    day: '2-digit',
    month: '2-digit',
    year: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
    hour12: false,
  });

  const parts = formatter.formatToParts(date);
  const get = (type) => parts.find(p => p.type === type)?.value || '';

  const weekdayRaw = get('weekday').toLowerCase();
  const weekday = weekdayRaw
    .replace('-feira', '')
    .replace('terca', 'terça')
    .replace('sabado', 'sábado');

  const day = get('day');
  const month = get('month');
  const year = get('year');
  const hour = Number(get('hour'));
  const minute = Number(get('minute'));

  const hourFormatted = formatHour(hour, minute);

  return {
    weekday,
    day,
    month,
    year,
    hour,
    minute,
    display: `${weekday}, ${day}/${month} às ${hourFormatted}`,
    shortDisplay: `${weekday} às ${hourFormatted}`,
    shift: getShift(hour),
  };
}


function getMinutesDiff(utcA, utcB) {
  const a = new Date(utcA).getTime();
  const b = new Date(utcB).getTime();
  return Math.abs((b - a) / 1000 / 60);
}

// Filtra só slots válidos e disponíveis
const slots = rawSlots
  .filter(slot => slot?.starts_at && (slot.available_bookings == null || slot.available_bookings > 0))
  .map(slot => {
    const local = getLocalParts(slot.starts_at);

    return {
      starts_at: slot.starts_at,
      ends_at: slot.ends_at || null,
      available_bookings: slot.available_bookings ?? null,
      local_weekday: local.weekday,
      local_day: local.day,
      local_month: local.month,
      local_year: local.year,
      local_hour: local.hour,
      local_minute: local.minute,
      local_shift: local.shift,
      display: local.display,
      short_display: local.shortDisplay,
    };
  })
  .sort((a, b) => new Date(a.starts_at) - new Date(b.starts_at));

if (slots.length === 0) {
  return [
    {
      json: {
        success: false,
        message: 'Nenhum horário disponível encontrado.',
        option_1: null,
        option_2: null,
        offered_slots: [],
      },
    },
  ];
}

const first = slots[0];
let second = null;

// 1. Procura slot com diferença mínima de 2h
second = slots.find((slot, index) => {
  if (index === 0) return false;
  return getMinutesDiff(first.starts_at, slot.starts_at) >= MIN_DIFF_MINUTES;
});

// 2. Se não achar, tenta slot no próximo turno
if (!second) {
  second = slots.find((slot, index) => {
    if (index === 0) return false;
    return slot.local_shift !== first.local_shift;
  });
}

// 3. Se ainda não achar, pega o próximo slot diferente do primeiro
if (!second) {
  second = slots.find((slot, index) => index > 0);
}

const offeredSlots = second ? [first, second] : [first];

return [
  {
    agenda_context: {
      success: true,
      timezone: TIMEZONE,
      rule: {
        first_option: 'slot mais próximo disponível',
        second_option: 'slot com diferença mínima de 30h; se não houver, próximo turno; se não houver, próximo slot disponível',
      },
      option_1: first
        ? {
            starts_at: first.starts_at,
            ends_at: first.ends_at,
            display: first.display,
            short_display: first.short_display,
            shift: first.local_shift,
          }
        : null,
      option_2: second
        ? {
            starts_at: second.starts_at,
            ends_at: second.ends_at,
            display: second.display,
            short_display: second.short_display,
            shift: second.local_shift,
          }
        : null,
      offered_slots: offeredSlots.map((slot, index) => ({
        option_id: `option_${index + 1}`,
        starts_at: slot.starts_at,
        ends_at: slot.ends_at,
        display: slot.display,
        short_display: slot.short_display,
        shift: slot.local_shift,
      })),
    },
    found_slots: true,
    option_1: first.short_display,
    option_1_start: first.starts_at,
    option_2: second.short_display,
    option_2_start: second.starts_at,
    whatsapp_message: second
      ? `Os próximos horários que tenhos disponível para sua avaliação são: \n*1. ${first.display}* ou \n*2. ${second.display}*. \nQual fica melhor para você?`
      : `Tenho somente um horário disponível nos próximos 7 dias para a avaliação: \n*1. ${first.display}*. \nEsse horário funciona para você?`,
  },
];

const base = $items('BASE CONSULTAR AGENDA', 0, 0)[0]?.json || {};
const agenda = items[0]?.json || {};

const pick = (...values) => {
  for (const v of values) {
    if (v !== undefined && v !== null && String(v).trim() !== '') return v;
  }
  return '';
};

const foundSlots = Boolean(
  agenda.found_slots === true ||
  (pick(agenda.option_1, agenda.option_1_display) && pick(agenda.option_2, agenda.option_2_display))
);

const option1 = pick(agenda.option_1, agenda.option_1_display);
const option1Start = pick(agenda.option_1_start);
const option2 = pick(agenda.option_2, agenda.option_2_display);
const option2Start = pick(agenda.option_2_start);
const mensagemFallback = pick(agenda.mensagem_fallback);

const next = {
  ...base,
  inputs: {
    ...(base.inputs || {})
  }
};

if (!next.inputs.resumo_lead || typeof next.inputs.resumo_lead !== 'object') {
  next.inputs.resumo_lead = {};
}

if (!next.inputs.agenda || typeof next.inputs.agenda !== 'object') {
  next.inputs.agenda = {};
}

next.inputs.deve_consultar_agenda = false;
next.inputs.deve_criar_pre_reserva = false;
next.inputs.deve_solicitar_pagamento = false;
next.inputs.deve_repassar_humano = false;
next.inputs.deve_encerrar_conversa = false;

if (foundSlots) {
  next.inputs.status_lead = 'AGUARDANDO_ESCOLHA_HORARIO';
  next.inputs.evento_sistema = 'HORARIOS_ENVIADOS';
  next.inputs.proxima_acao = 'aguardar o lead escolher um dos horários enviados';

  next.inputs.agenda = {
    ...(next.inputs.agenda || {}),
    option_1: option1,
    option_1_start: option1Start,
    option_2: option2,
    option_2_start: option2Start
  };

  next.inputs.mensagens_resposta = [
    'Perfeito. Tenho estes dois horários para a avaliação:',
    `1) ${option1}\n2) ${option2}`,
    'Qual deles fica melhor para você?'
  ];
} else {
  next.inputs.status_lead = next.inputs.status_lead || 'COMPROVANTE_RECEBIDO';
  next.inputs.evento_sistema = 'AGENDA_CONSULTADA';
  next.inputs.proxima_acao = 'pedir melhor dia da semana ou período para consultar novas opções';

  next.inputs.mensagens_resposta = [
    mensagemFallback || 'Consultei a agenda aqui e não consegui te passar duas opções fechadas agora.',
    'Me diz qual o melhor dia da semana ou período para você que eu verifico novas opções.'
  ];
}

next.message = {
  ...(next.message || {}),
  clean_answer: (next.inputs.mensagens_resposta || []).join('\n\n')
};

return [{ json: next }];

