const item = $input.first().json;

const sanitize = (value) =>
  String(value || '')
    .replace(/\[object Object\]/gi, '')
    .replace(/[\u200B-\u200D\u2060\uFEFF]/g, ' ')
    .replace(/\uFFFD/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();

const currentMessageRaw =
  item?.message?.content_normalized ||
  item?.message?.content_raw ||
  item?.message?.content ||
  item?.last_user_message ||
  '';

const historyRaw =
  item?.history_for_crm ||
  item?.historico ||
  item?.chat_history ||
  '';

const currentMessageNormalized = sanitize(currentMessageRaw);
const historyNormalized = sanitize(historyRaw);

item.message = item.message || {};
item.message.content_for_router = currentMessageNormalized;

item.contexto_router = {
  mensagem_atual: currentMessageNormalized,
  historico_normalizado: historyNormalized,
  texto_base_para_router: [
    currentMessageNormalized,
    historyNormalized
  ].filter(Boolean).join('\n\n')
};

item.last_user_message = currentMessageNormalized;
item.history_for_router_normalized = historyNormalized;

return [{ json: item }];
